INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('ecf6ee8e-8b73-493f-af64-7e12f7a13f2d', 'המנהיגות הבאות של ישראל', 'active', 'תוכנית “המנהיגות הבאות של ישראל” היא תוכנית ארצית לפיתוח מנהיגות נשית צעירה בזירה הציבורית והפוליטית, הפועלת בקמפוסים ברחבי הארץ. התוכנית נועדה להתמודד עם ייצוג חסר של נשים במוקדי קבלת החלטות, ומעניקה לסטודנטיות ידע מקצועי, כלים מעשיים, ליווי אישי ורשת קשרים במטרה לחזק את מעורבותן הציבורית ולעודד השתלבות בתפקידי הנהגה והשפעה במדינת ישראל. במסגרת התוכנית מתקיימים עשרה מפגשים שבועיים, סדנאות, סיורים והכשרות עם נשות מקצוע מהשדה הציבורי, לצד בניית קהילה תומכת של משתתפות ובוגרות הפועלות לקידום שינוי חברתי.', 'פרויקטים', '{}', '2026-05-04T13:20:48.869Z', '2026-05-04T16:54:31.131Z', '2026', 'https://docs.google.com/document/d/1UHVGk4mL06l8Jk0quq5BWIRwCIUur2ZDcK_Dyk3CD4g/edit?usp=sharing', '{}', '', '', '', NULL, NULL, '[]', '[]', '[]', '[]', '', '[]', FALSE) ON CONFLICT DO NOTHING;
INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('1856dffc-79a7-4aee-a93b-6a0c9bee2160', 'האחווה הסטודנטיאלית הגאה', 'active', 'התארגנות סטודנטיאלית להט"בית שיוצרת קהילות ופועלת ביותר מ- 30 קמפוסים ברחבי הארץ.
INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('b1bdbad4-69c0-485e-ac89-bce6005a004c', 'ועידת הצעירים בדיקה', 'archived', NULL, 'הנהלה', '{}', '2026-05-05T11:29:07.513Z', '2026-05-20T10:24:11.566Z', '2206', NULL, '{}', '', '', '', NULL, NULL, '[]', '[{"id":"99777106-a52d-466b-9338-b4e63652b02c","body":"@דניאל","author":"יאיר","mentions":[],"created_at":"2026-05-17T08:29:12.804Z","authorUsername":"יאיר"}]', '[{"at":"2026-05-20T10:24:11.563Z","by":"דניאל סי","id":"7124750b-e5f8-4abc-80a1-9de1e20df7d8","action":"field_status","summary":"שינה סטטוס","byDisplay":"דניאל סי"}]', '[]', '', '[]', FALSE) ON CONFLICT DO NOTHING;
INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('f3bc24ae-899e-4612-852b-42c506345f17', 'תוכניות ההכשרה המקצועיות גאות', 'active', '', 'האחווה הגאה', '{}', '2026-05-04T13:52:01.918Z', '2026-05-04T16:48:20.608Z', NULL, NULL, '[]', '', '', '', NULL, NULL, '[]', '[]', '[]', '[]', '', '[]', FALSE) ON CONFLICT DO NOTHING;
INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('49b3bd3a-88e1-42f3-b3f0-c817590f93a1', 'עתיד ותיק - עורף ברזל', 'active', 'עתיד ותיק הינו פרויקט של המשרד לשוויון חברתי וקידום מעמד האישה בשיתוף התאחדות הסטודנטים והסטודנטיות הארצית ומפעל הפיס.
INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('75e7608f-bdd2-4c4a-8c9d-e5805454e8ed', 'אמאן - עורף ברזל', 'active', 'משרד לשוויון חברתי וקידום מעמד האישה בשיתוף התאחדות הסטודנטים והסטודנטיות הארצית ומפעל הפיס יוצאים בפרויקט מלגות אמאן "أمان" במסגרת המלגה, הסטודנטים/ות ישתלבו בעשייה מגוונת ברשויות מקומיות ערביות ובערים מעורבות.
INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('aa61a2c8-6d57-46a1-89dd-ede89b8b3a15', 'משפיעים בלימודים', 'active', 'משפיעים בלימודים" היא תכנית מלגות קיום ייחודית שמעניקה לחיילים וחיילות משוחררים הזדמנות לשלב בין לימודים אקדמיים או טכנולוגיים לבין עשייה חברתית משמעותית בקהילה.
INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('fa36b27c-c4b3-40de-88e9-e2627cffe539', 'חבר כלבבי', 'active', 'תכנית המלגות "חבר כלבבי" הינה תכנית ייחודית ומשותפת של התאחדות הסטודנטים/ות הארצית, משרד החקלאות, עמותות S.O.S חיות וכלבלאב, עיריית אשקלון, אשכול נגב מערבי וקרן פילנתרופית תומכת.
INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('76617645-3e46-48af-a795-df3ab7663053', 'עו"סים טוב', 'active', 'ארועי ה-7 באוקטובר ומלחמת חרבות ברזל הותירו צלקות עמוקות בחברה הישראלית. בעקבות האבדות הכבדות, הפגיעות בגוף ובנפש, והטראומה הקולקטיבית, עלה הצורך החיוני בחיזוק קצועות הטיפול, ובפרט בעובדים סוציאליים. אנשי מקצוע אלה ניצבים בחזית הטיפול בטראומה אותה חווים נפגעי המלחמה, כולל נפגעי פעולות איבה, מפונים, משפחות שכולות ומשפחות החטופים.
INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('8df3771b-92ae-40f8-b49b-5b2c456e5f3a', 'משחקים הוגן - מרכז פרס לשלום', 'active', 'פרויקט ייחודי של מרכז פרס, במסגרתו נפגשים ילדים וילדות יהודים וערבים מקהילות שונות בישראל במטרה לחבר בין המגזרים השונים בעזרת משחק הכדורגל .התכנית פועלת לאורך שנת הלימודים בשיתוף בתי ספר מכל רחבי הארץ.', 'מלגות - קורל', '{}', '2026-05-14T07:52:00.985Z', '2026-05-14T07:52:00.985Z', '2025', NULL, '{}', '', '', '', NULL, NULL, '[]', '[]', '[]', '[]', '', '[]', FALSE) ON CONFLICT DO NOTHING;
INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('7d327e71-bdc6-4a4b-b68c-942c4801d0b0', 'קשב ופילוג', 'archived', 'תוכנית שקמה בשיתוף פעולה בין התאחדות הסטודנטים והסטודנטיות הארצית לארגון גשר במטרה לקדם שיח מכיל ובונה הנוגע לסוגיות מורכבות ושונות בחברה הישראלי.
INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('052aaaa9-cbfa-4db9-81f2-5b3bc0fb63f3', 'ריטריט הקשבה', 'active', 'סוף השבוע (חמישי-שבת) יתקיים במסגרת ריטריט הקשבה -
INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('f89ba654-0079-435f-b40f-152efa65b773', 'חוסן באקדמיה - הקואליציה הישראלית לטראומה', 'active', 'המיזם קם בעקבות אירועי 7 באוקטובר ומלחמת חרבות ברזל, מתוך הבנה עמוקה בצורך לחזק את חוסנו הנפשי והקהילתי של המרחב האקדמי: המכיל קהילות של עשרות אלפי סטודנטיות וסטודנטים, סגל אקדמי ומנהלי.
INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('2926511a-8b1f-47fe-b38d-eb1d73c5610c', 'סטודנטספיק STUDENTSPEAK', 'active', 'תכנית ללימוד ושיפור השפה האנגלית המדוברת מטעם התאחדות הסטודנטים והסטודנטיות הארצית בשיתוף פר"ח וברלינגטון אינגליש-הרשת הגדולה בישראל ללימודי אנגלית.
INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('4ccb14d2-a092-4f76-8df2-bd8d51adee7e', 'אקדמי לינק', 'active', ' קהילות סטודנטיאליות שפועלות ברחבי הארץ ויוצרות יחד מרחב בטוח ומשמעותי לסטודנטים/יות עם וללא מוגבלות. בתוכנית תמצאו מקום לשתף, ללמוד ולהוביל שינוי אמיתי. "אקדמי-לינק" יהווה תשתית אסטרטגית לקידום שוויון הזדמנויות לצעירים וצעירות עם מוגבלות באקדמיה, בתעסוקה ובחברה זאת על ידי יצירת מרחב אקדמי שוויוני ונגיש לכל הסטודנטים/יות.', 'מדיניות חברתית+פרויקטים', '{}', '2026-05-04T13:52:09.826Z', '2026-05-17T08:33:14.697Z', NULL, 'https://drive.google.com/drive/folders/18xqjxcGHxGhbxJjIgVszx6n_okldq-EP?usp=sharing', '[{"url":"https://docs.google.com/document/d/1p12zR-jVFFtRwp7sCkuuE8KvppnR4xjR6if4pKaTHIU/edit?usp=sharing","name":"תיק יסוד 2026"}]', 'בעבודה', '', '', NULL, NULL, '[]', '[]', '[{"at":"2026-05-17T08:27:45.164Z","by":"דניאל סי","id":"2461b6c3-3c96-4719-8cc4-c8312f869d95","action":"field_drive_link","summary":"שינה קישור Drive","byDisplay":"דניאל סי"},{"at":"2026-05-17T08:33:14.694Z","by":"דניאל סי","id":"769724fb-5536-4fa2-8ddb-25220b849442","action":"field_stage","summary":"שינה שלב","byDisplay":"דניאל סי"}]', '[]', '', '[]', FALSE) ON CONFLICT DO NOTHING;
INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('c55f6570-7d7b-4bab-9400-2f6ab820ce59', 'מדברים ערבית', 'active', '"מדברים ערבית" היא תכנית ללימוד השפה הערבית המדוברת של ההתאחדות בשיתוף פר"ח ומדרסה.
INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('ec64d83d-35df-47f9-92c5-4d545f983b36', 'שלבים', 'active', NULL, NULL, '{}', '2026-05-28T07:59:38.423Z', '2026-05-28T07:59:43.985Z', NULL, NULL, '[]', '', '', 'יאיר', NULL, NULL, '[]', '[]', '[{"at":"2026-05-28T07:59:43.985Z","by":"דניאל סי","id":"fb8473ee-a5da-4730-87a0-2bd485b58381","action":"field_owner","summary":"שינה אחראי","byDisplay":"דניאל סי"}]', '[]', '', '[]', FALSE) ON CONFLICT DO NOTHING;
INSERT INTO "projects" ("id", "title", "status", "description", "leading_department", "field_labels", "created_at", "updated_at", "activity_year", "drive_link", "attachments", "stage", "priority", "owner", "due_date", "start_date", "tasks", "comments", "change_history", "labels", "goal", "metrics", "is_template") VALUES ('41e27203-9798-44da-b91b-9b26a844414f', 'אנחנו על זה', 'active', 'תוכנית "אנחנו על זה" היא מיזם משותף של התאחדות הסטודנטים/יות ועמותת נט"ל, שמטרתו לספק מענה לסטודנטים/יות שנפגעו ישירות או באופן עקיף ממלחמת "חרבות ברזל" והמערכות הנלוות, במיוחד אלו המשתייכים למעגל הפגיעה הראשון – משרתי/ות מילואים, נפגעי/ות פעולות איבה, מפונים/ות, משפחות חטופים ומשפחות שכול. התוכנית מספקת ליווי סטודנטיאלי פרטני וסיוע אקדמי, תוך שילוב והכשרת סטודנטים/יות ממקצועות טיפול (תואר ראשון בשנים מתקדמות או שני בעבודה סוציאלית/פסיכולוגיה) תחת הדרכה מטעם נט"ל. הליווי כולל פיתוח אישי, תמיכה אקדמית, ניהול זמנים ומשימות וכלים להתמודדות עם אתגרים נפשיים, לימודיים וכלכליים, במטרה לאפשר לסטודנטים/יות לשמור על רצף לימודים, להפחית נשירה ולתרום לחוסנם האישי והחברתי. הפרויקט החל לפעול בשנת תשפ"ה וממשיך לשנת תשפ"ו.', NULL, '{}', '2026-06-18T07:46:32.063Z', '2026-06-18T08:31:37.049Z', NULL, NULL, '[]', '', '', 'מיכל אלטשולר', NULL, NULL, '[]', '[]', '[{"at":"2026-06-18T08:31:37.053Z","by":"דניאל סי","id":"7087c586-8b9a-4987-842a-8dbe1f8cf197","action":"field_owner","summary":"שינה אחראי","byDisplay":"דניאל סי"}]', '[]', '', '[]', FALSE) ON CONFLICT DO NOTHING;
